import React from 'react';
function formatValue(value) {
    if (typeof value === 'boolean') {
        return value ? 'Yes' : 'No';
    }
    if (Array.isArray(value)) {
        return value.map(v => `"${v}"`).join(', ');
    }
    return value;
}
